+function matchesErrorClass(error: Error, superJson: SuperJSON): boolean {
+  const filter = superJson.errorStackOptions?.classFilter ?? [];
+  return filter.length === 0 || filter.includes(error.name);
+}
+
+function usesErrorStackMode(
+  error: Error,
+  superJson: SuperJSON,
+  mode?: 'string' | 'frames'
+): boolean {
+  const configuredMode = superJson.errorStackOptions?.mode;
+  return (
+    configuredMode !== undefined &&
+    configuredMode !== 'off' &&
+    matchesErrorClass(error, superJson) &&
+    (mode === undefined || configuredMode === mode)
+  );
+}
+
+function serializeError(v: Error, superJson: SuperJSON): Record<string, any> {
+  const options = superJson.errorStackOptions;
+  const applies = usesErrorStackMode(v, superJson);
+  const baseError: Record<string, any> = {
+    name: v.name,
+    message:
+      applies && options?.sanitizeMessage ? sanitizeMessage(v.message) : v.message,
+  };
+
+  if (!options) {
+    if ('cause' in v) baseError.cause = (v as any).cause;
+  } else if (options.includeCauses !== 'none' && 'cause' in v) {
+    const cause = (v as any).cause;
+    const remaining = superJson.getErrorCauseDepth(v);
+    if (cause instanceof Error && remaining > 0) {
+      superJson.setErrorCauseDepth(cause, remaining - 1);
+      baseError.cause = cause;
+    }
+  }
+
+  if (options && 'errors' in (v as any)) {
+    baseError.errors = (v as any).errors;
+  }
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (options && (prop === 'stack' || prop === 'stackFrames')) return;
+    baseError[prop] = (v as any)[prop];
