    at /tmp/example.ts:1:1\\r\
    at ignored';
+
+    const serialized = superjson.serialize(error);
+    expect(serialized.json).toMatchObject({
+      stack: 'Error: nope\
at /tmp/example.ts:1:1',
+    });
+    expect(serialized.meta?.values).toEqual(['Error/stack']);
+    expect(superjson.deserialize<any>(serialized).stack).toBe(
+      'Error: nope\
at /tmp/example.ts:1:1'
+    );
+  });
+
+  test('uses frame annotations and preserves supported frame values', () => {
+    const superjson = new SuperJSON({ errorStack: { mode: 'frames' } });
+    superjson.allowErrorProps('stackFrames');
+    const error = new Error('nope');
+    error.stack = 'Error: nope\
    at file.ts:1:1';
+    const serialized = superjson.serialize({ error, values: new Set([1]) });
+    expect((serialized.json as any).error.stackFrames).toEqual([
+      { raw: 'Error: nope' },
+      { raw: 'at file.ts:1:1' },
+    ]);
